-- COMBI SEASON Mundial - fase de grupos FIFA World Cup 2026.
-- Fuente base: PDF oficial FIFA "FWC26 Match Schedule", version 10 Apr 2026.
-- FIFA publica los horarios en ET; aqui se guardan convertidos a UTC (+00:00).
-- Ejecutar despues de supabase/2026-05-31-calendar-schema.sql.

delete from public.matches
where match_number is null;

on conflict (match_number) do update set
  match_date = excluded.match_date,
  phase = excluded.phase,
  group_code = excluded.group_code,
  home_team = excluded.home_team,
  away_team = excluded.away_team,
  status = excluded.status,
  source = excluded.source;
